    AND id = #{query.orderId}
    AND user_id = #{query.userId}
    AND biz_type = #{query.bizType.code}
    AND order_status = #{query.orderStatus}
    AND pay_status = #{query.payStatus}
    AND created >= #{query.startTime}
    AND created <= #{query.endTime}
